const body = $json.body || $json;
if (!body.provider || !body.input) throw new Error('provider + input required');
const input = body.input;
const buyer = input.buyer || {};
// Modifier classification
const hasTaxId = !!buyer.taxId;
const hasCarrier = !!buyer.carrier;
const hasLoveCode = !!buyer.loveCode;
const hasMixedTax = Array.isArray(input.items) && new Set(input.items.map(i => i.taxType).filter(Boolean)).size > 1;
// B2B vs B2C exclusivity rules
if (hasTaxId && (hasCarrier || hasLoveCode)) throw new Error('B2B (taxId) cannot coexist with carrier/loveCode (B2C-only modifiers)');
if (hasCarrier && hasLoveCode) throw new Error('carrier and loveCode are mutually exclusive');
if (hasTaxId && !buyer.name) throw new Error('B2B issue requires buyer.name (company full name)');
return [{ json: {
  correlationId: `inv-issue-b2b-${Date.now()}-${Math.floor(Math.random()*1e6)}`,
  startedAt: new Date().toISOString(),
  provider: body.provider,
  input,
  classification: {
    flavor: hasTaxId ? 'B2B' : 'B2C',
    modifiers: {
      b2b: hasTaxId,
      mixedTax: hasMixedTax,
      carrier: hasCarrier,
      loveCode: hasLoveCode
    }
  }
}}];

const state = $('Stamp + classify modifiers').first().json;
const statusCode = Number($json.statusCode ?? 0);
const respBody = $json.body ?? $json;
const ok = statusCode >= 200 && statusCode < 300;
const unsupported = statusCode === 400 && respBody?.error?.code === 'UNSUPPORTED';
return [{ json: {
  ...state,
  statusCode,
  ok,
  unsupported,
  status: ok ? 'issued' : (unsupported ? 'unsupported-by-provider' : 'failed'),
  invoiceNumber: ok ? respBody?.result?.invoiceNumber : null,
  errorCode: respBody?.error?.code ?? null,
  errorMessage: respBody?.error?.message ?? null,
  appliedAt: new Date().toISOString()
} }];
